import { useEffect, useState } from "react";
import { motion } from "framer-motion";
import { Coins, TrendUp, Users } from "@phosphor-icons/react";
import axios from "axios";

const API = `${process.env.REACT_APP_BACKEND_URL}/api`;

export default function Home() {
  const [students, setStudents] = useState([]);
  const [bankBalance, setBankBalance] = useState(0);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadStudents();
    loadBank();
    
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible') {
        loadStudents();
        loadBank();
      }
    };
    
    window.addEventListener('focus', () => { loadStudents(); loadBank(); });
    document.addEventListener('visibilitychange', handleVisibilityChange);
    
    return () => {
      window.removeEventListener('focus', () => { loadStudents(); loadBank(); });
      document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, []);

  const loadStudents = async () => {
    try {
      const response = await axios.get(`${API}/students`);
      setStudents(response.data);
    } catch (error) {
      console.error("Erro ao carregar alunos:", error);
    } finally {
      setLoading(false);
    }
  };

  const loadBank = async () => {
    try {
      const response = await axios.get(`${API}/bank`);
      setBankBalance(response.data.balance);
    } catch (error) {
      console.error("Erro ao carregar banco:", error);
    }
  };

  const totalGamas = students.reduce((sum, student) => sum + student.balance, 0);
  const avgGamas = students.length > 0 ? Math.round(totalGamas / students.length) : 0;
  const topStudent = students.length > 0 ? students.reduce((max, student) => student.balance > max.balance ? student : max, students[0]) : null;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 py-6 sm:py-12">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <div className="text-center mb-12">
          <h1 className="text-3xl sm:text-5xl md:text-6xl lg:text-7xl font-black tracking-tighter mb-4" style={{ fontFamily: 'Unbounded, sans-serif', color: '#6BB4E8' }}>
            Sistema de <span className="text-[#4A90C8]">GAMAS</span>
          </h1>
          <p className="text-lg md:text-xl text-[#4A90C8] max-w-2xl mx-auto">
            Ganhe gamas realizando atividades e troque por benefícios incríveis!
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.1 }}
            className="neo-card p-8"
            data-testid="bank-balance-card"
          >
            <div className="flex items-start justify-between">
              <div>
                <p className="text-[#4A90C8] font-semibold mb-2">Banco de Gamas</p>
                <p className="text-5xl font-black gama-number" style={{ fontFamily: 'Unbounded, sans-serif' }}>
                  {bankBalance}
                </p>
              </div>
              <div className="p-3 bg-[#E8F4FA] rounded-lg border-2 border-[#6BB4E8]">
                <Coins size={32} weight="bold" className="text-[#6BB4E8]" />
              </div>
            </div>
          </motion.div>

          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
            className="neo-card p-8"
            data-testid="total-gamas-card"
          >
            <div className="flex items-start justify-between">
              <div>
                <p className="text-[#4A90C8] font-semibold mb-2">Total de Gamas (Alunos)</p>
                <p className="text-5xl font-black gama-number" style={{ fontFamily: 'Unbounded, sans-serif' }}>
                  {totalGamas}
                </p>
              </div>
              <div className="p-3 bg-[#E8F4FA] rounded-lg border-2 border-[#6BB4E8]">
                <Coins size={32} weight="bold" className="text-[#6BB4E8]" />
              </div>
            </div>
          </motion.div>

          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
            className="neo-card p-8"
            data-testid="avg-gamas-card"
          >
            <div className="flex items-start justify-between">
              <div>
                <p className="text-[#4A90C8] font-semibold mb-2">Média de Gamas</p>
                <p className="text-5xl font-black gama-number" style={{ fontFamily: 'Unbounded, sans-serif' }}>
                  {avgGamas}
                </p>
              </div>
              <div className="p-3 bg-[#E8F4FA] rounded-lg border-2 border-[#6BB4E8]">
                <TrendUp size={32} weight="bold" className="text-[#6BB4E8]" />
              </div>
            </div>
          </motion.div>

          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
            className="neo-card p-8"
            data-testid="total-students-card"
          >
            <div className="flex items-start justify-between">
              <div>
                <p className="text-[#4A90C8] font-semibold mb-2">Total de Alunos</p>
                <p className="text-5xl font-black gama-number" style={{ fontFamily: 'Unbounded, sans-serif' }}>
                  {students.length}
                </p>
              </div>
              <div className="p-3 bg-[#E8F4FA] rounded-lg border-2 border-[#6BB4E8]">
                <Users size={32} weight="bold" className="text-[#6BB4E8]" />
              </div>
            </div>
          </motion.div>
        </div>

        {topStudent && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.4 }}
            className="neo-card p-8 mb-12"
            data-testid="top-student-card"
          >
            <div className="text-center">
              <p className="text-[#4A90C8] font-semibold mb-3">🏆 Aluno Destaque</p>
              <h2 className="text-4xl font-black tracking-tighter mb-2" style={{ fontFamily: 'Unbounded, sans-serif', color: '#6BB4E8' }}>
                {topStudent.name}
              </h2>
              <p className="text-6xl font-black gama-number" style={{ fontFamily: 'Unbounded, sans-serif' }}>
                {topStudent.balance} GAMAS
              </p>
            </div>
          </motion.div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <motion.div
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: 0.5 }}
            className="neo-card p-8"
          >
            <h3 className="text-2xl font-black tracking-tighter mb-4" style={{ fontFamily: 'Unbounded, sans-serif' }}>
              Como Funciona?
            </h3>
            <ul className="space-y-3 text-[#4B5563]">
              <li className="flex items-start gap-3">
                <span className="text-[#6BB4E8] font-bold text-xl">1.</span>
                <span>Realize atividades e participe das aulas para ganhar gamas</span>
              </li>
              <li className="flex items-start gap-3">
                <span className="text-[#6BB4E8] font-bold text-xl">2.</span>
                <span>Acumule seus gamas no seu saldo pessoal</span>
              </li>
              <li className="flex items-start gap-3">
                <span className="text-[#6BB4E8] font-bold text-xl">3.</span>
                <span>Troque seus gamas por benefícios exclusivos</span>
              </li>
            </ul>
          </motion.div>

          <motion.div
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: 0.6 }}
            className="neo-card p-8 bg-[#6BB4E8] text-white border-[#6BB4E8]"
          >
            <h3 className="text-2xl font-black tracking-tighter mb-4" style={{ fontFamily: 'Unbounded, sans-serif' }}>
              Dicas para Ganhar Mais!
            </h3>
            <ul className="space-y-3">
              <li className="flex items-start gap-3">
                <span className="font-bold text-xl">•</span>
                <span>Participe ativamente de todas as aulas</span>
              </li>
              <li className="flex items-start gap-3">
                <span className="font-bold text-xl">•</span>
                <span>Ajude seus colegas com dúvidas</span>
              </li>
              <li className="flex items-start gap-3">
                <span className="font-bold text-xl">•</span>
                <span>Entregue trabalhos sempre no prazo</span>
              </li>
              <li className="flex items-start gap-3">
                <span className="font-bold text-xl">•</span>
                <span>Traga sua apostila completa todos os dias</span>
              </li>
              <li className="flex items-start gap-3">
                <span className="font-bold text-xl">•</span>
                <span>Faça resumos criativos das aulas</span>
              </li>
              <li className="flex items-start gap-3">
                <span className="font-bold text-xl">•</span>
                <span>Transfira gamas entre amigos de forma responsável</span>
              </li>
            </ul>
          </motion.div>
        </div>
      </motion.div>
    </div>
  );
}